// One-off: screenshot the self-contained print/PDF document produced by
// tine-core's page_print_html (generated by the ignored `gen_sample_export` test
// at /tmp/tine-sample-export/print-sample.html). Verifies the print CSS + render.
import { chromium } from "playwright";
import { pathToFileURL } from "node:url";

const src = process.argv[2] || "/tmp/tine-sample-export/print-sample.html";
const out = process.argv[3] || "/tmp/claude-3042/-aux-koutecky-logseq/5a8edc2b-663a-4ee8-b183-325ec619c4d9/scratchpad/printdoc.png";

const browser = await chromium.launch();
const page = await browser.newPage({ viewport: { width: 820, height: 1100 } });
await page.goto(pathToFileURL(src).href, { waitUntil: "networkidle" });
// Give KaTeX/hljs (CDN) a moment to typeset.
await page.waitForTimeout(1500);
await page.screenshot({ path: out, fullPage: true });
// Also emit the print-media rendering (what the PDF actually looks like).
await page.emulateMedia({ media: "print" });
await page.waitForTimeout(200);
await page.screenshot({ path: out.replace(/\.png$/, "-print.png"), fullPage: true });
await browser.close();
console.log("wrote", out);
